package ingest

import "testing"

func TestExtractSectionID(t *testing.T) {
	tests := []struct {
		heading   string
		wantID    string
		wantTitle string
	}{
		// Lettered
		{"A.1 - Trust in Claims", "A.1", "Trust in Claims"},
		{"B.2.3 Complex Pattern", "B.2.3", "Complex Pattern"},
		{"A.1 Trust in Claims", "A.1", "Trust in Claims"},

		// Numbered with dot
		{"3. Getting Started", "3", "Getting Started"},
		{"12. Advanced Usage", "12", "Advanced Usage"},

		// Simple number
		{"3 Getting Started", "3", "Getting Started"},

		// Slug fallback
		{"My Custom Section", "my-custom-section", "My Custom Section"},
		{"Error Handling & Retry", "error-handling-retry", "Error Handling & Retry"},

		// Edge cases
		{"", "untitled", ""},
	}

	for _, tt := range tests {
		t.Run(tt.heading, func(t *testing.T) {
			gotID, gotTitle := ExtractSectionID(tt.heading)
			if gotID != tt.wantID {
				t.Errorf("ExtractSectionID(%q) id = %q, want %q", tt.heading, gotID, tt.wantID)
			}
			if gotTitle != tt.wantTitle {
				t.Errorf("ExtractSectionID(%q) title = %q, want %q", tt.heading, gotTitle, tt.wantTitle)
			}
		})
	}
}
